// src/app/screens/LoadScreen.ts
import * as PIXI from "pixi.js";
import { CreationEngine } from "../../engine/engine";

export class LoadScreen extends PIXI.Container {
  constructor(private engine: CreationEngine) {
    super();

    const text = new PIXI.Text("Loading...", {
      fontFamily: "Arial",
      fontSize: 24,
      fill: 0xffffff,
    });
    text.position.set(engine.renderer.width / 2, engine.renderer.height / 2);
    text.anchor.set(0.5);
    this.addChild(text);

    // Simulate loading
    setTimeout(() => {
      this.emit("dismiss");
    }, 1000);
  }
}
